from scipy.optimize import minimize

def run_and_analyze(circuit, aer_sim, graph):
    transpiled_circuit = transpile(circuit, aer_sim)

    def objective(params):
        binds = {}
        for i in range(circuit.num_parameters):
            binds[circuit.parameters[i]] = [float(params[i])]
        parameter_binds = [binds]

        job = aer_sim.run(transpiled_circuit, parameter_binds=parameter_binds, shots=1024)
        result = job.result()
        counts = result.get_counts()
        if isinstance(counts, list):
            counts = counts[0]

        converted_counts = {state[::-1]: count for state, count in counts.items()}
        return -compute_expectation(converted_counts, graph)

    initial_params = [0.5] * circuit.num_parameters
    res = minimize(objective, initial_params, method='COBYLA')

    opt_params = res.x
    binds = {}
